  ('G001', 'Cabernet Sauvignon', 'The undisputed king of red wines, producing full-bodied wines with blackcurrant, cedar, and spice notes. It thrives in warm climates and forms the backbone of Bordeaux''s legendary blends.', 'GRAPES', array['Blackcurrant', 'Cedar', 'Spice']::text[], '#722F37', 'droplet', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Blackcurrant","icon":"circle","color":"#4B0082"},{"note":"Cedar","icon":"mountain","color":"#8B4513"},{"note":"Spice","icon":"triangle","color":"#D2691E"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Vidure","Petit-Cabernet"],"keyRegions":["Bordeaux","Napa Valley"],"body":"Full-Bodied Red"}'::jsonb, 'NOBLE', '{"id":"G001","name":"Cabernet Sauvignon","type":"red","style":"Full-Bodied Red","styleId":"noble-grapes","countryOfOrigin":"France","alternateNames":["Vidure","Petit-Cabernet"],"rarityTier":"noble","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blackcurrant","Cedar","Spice"],"notableRegions":["Bordeaux","Napa Valley"],"info":"The undisputed king of red wines, producing full-bodied wines with blackcurrant, cedar, and spice notes. It thrives in warm climates and forms the backbone of Bordeaux''s legendary blends.","evolutionLine":[],"regionAffinity":[{"region":"Bordeaux","bonus":"+1 Focus"},{"region":"Napa Valley","bonus":"+1 Focus"}]}'::jsonb),
  ('G002', 'Pinot Noir', 'Known as the heartbreak grape for its difficulty to grow, it produces elegant wines with cherry and earthy notes. This thin-skinned variety expresses terroir like no other grape.', 'GRAPES', array['Cherry', 'Earth', 'Floral']::text[], '#C48B8B', 'droplet', 'grape', 'grape', 'Light-Bodied Red', '[{"note":"Cherry","icon":"circle","color":"#DC143C"},{"note":"Earth","icon":"leaf","color":"#556B2F"},{"note":"Floral","icon":"sun","color":"#FF69B4"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Spätburgunder","Pinot Nero","Blauburgunder"],"keyRegions":["Burgundy","Oregon"],"body":"Light-Bodied Red"}'::jsonb, 'NOBLE', '{"id":"G002","name":"Pinot Noir","type":"red","style":"Light-Bodied Red","styleId":"noble-grapes","countryOfOrigin":"France","alternateNames":["Spätburgunder","Pinot Nero","Blauburgunder"],"rarityTier":"noble","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":2},"tastingProfile":["Cherry","Earth","Floral"],"notableRegions":["Burgundy","Oregon"],"info":"Known as the heartbreak grape for its difficulty to grow, it produces elegant wines with cherry and earthy notes. This thin-skinned variety expresses terroir like no other grape.","evolutionLine":[],"regionAffinity":[{"region":"Burgundy","bonus":"+1 Focus"},{"region":"Oregon","bonus":"+1 Focus"}]}'::jsonb),
  ('G003', 'Chardonnay', 'The world''s most versatile white grape, acting as a canvas for winemakers to craft everything from crisp to buttery styles. It responds beautifully to oak aging and malolactic fermentation.', 'GRAPES', array['Apple', 'Butter', 'Vanilla']::text[], '#C9A227', 'sun', 'grape', 'grape', 'Full-Bodied White', '[{"note":"Apple","icon":"circle","color":"#FACC15"},{"note":"Butter","icon":"cloud","color":"#F0E68C"},{"note":"Vanilla","icon":"sparkles","color":"#DEB887"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Morillon","Beaunois"],"keyRegions":["Burgundy","Napa"],"body":"Full-Bodied White"}'::jsonb, 'NOBLE', '{"id":"G003","name":"Chardonnay","type":"white","style":"Full-Bodied White","styleId":"noble-grapes","countryOfOrigin":"France","alternateNames":["Morillon","Beaunois"],"rarityTier":"noble","characteristics":{"tannin":3,"acid":3,"colorIntensity":2,"aromatics":5,"body":5},"tastingProfile":["Apple","Butter","Vanilla"],"notableRegions":["Burgundy","Napa"],"info":"The world''s most versatile white grape, acting as a canvas for winemakers to craft everything from crisp to buttery styles. It responds beautifully to oak aging and malolactic fermentation.","evolutionLine":[],"regionAffinity":[{"region":"Burgundy","bonus":"+1 Focus"},{"region":"Napa","bonus":"+1 Focus"}]}'::jsonb),
