  ('G010', 'Grenache', 'A sweet red fruit-driven grape that produces wines high in alcohol with strawberry and raspberry flavors. It is a key component in Southern Rhône blends and Spanish Garnacha wines.', 'GRAPES', array['Strawberry', 'Raspberry', 'Pepper']::text[], '#C48B8B', 'flame', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Strawberry","icon":"circle","color":"#FF69B4"},{"note":"Raspberry","icon":"circle","color":"#DC143C"},{"note":"Pepper","icon":"triangle","color":"#D3D3D3"}]'::jsonb, null, null, '{"origin":"Spain","synonyms":["Garnacha","Cannonau"],"keyRegions":["Rhône","Priorat"],"body":"Medium-Bodied Red"}'::jsonb, 'COMMON', '{"id":"G010","name":"Grenache","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Spain","alternateNames":["Garnacha","Cannonau"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Strawberry","Raspberry","Pepper"],"notableRegions":["Rhône","Priorat"],"info":"A sweet red fruit-driven grape that produces wines high in alcohol with strawberry and raspberry flavors. It is a key component in Southern Rhône blends and Spanish Garnacha wines.","evolutionLine":[],"regionAffinity":[{"region":"Rhône","bonus":"+1 Focus"},{"region":"Priorat","bonus":"+1 Focus"}]}'::jsonb),
  ('G011', 'Tempranillo', 'Spain''s noble grape variety, producing elegant wines with leather, tobacco, and red berry notes. It is the backbone of Rioja and Ribera del Duero, aging beautifully in American oak.', 'GRAPES', array['Fig', 'Tobacco', 'Dill']::text[], '#800020', 'shield', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Fig","icon":"circle","color":"#8B4513"},{"note":"Tobacco","icon":"cloud","color":"#A0522D"},{"note":"Dill","icon":"leaf","color":"#556B2F"}]'::jsonb, null, null, '{"origin":"Spain","synonyms":["Tinto Fino","Cencibel"],"keyRegions":["Rioja"],"body":"Medium-Bodied Red"}'::jsonb, 'COMMON', '{"id":"G011","name":"Tempranillo","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Spain","alternateNames":["Tinto Fino","Cencibel"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Fig","Tobacco","Dill"],"notableRegions":["Rioja"],"info":"Spain''s noble grape variety, producing elegant wines with leather, tobacco, and red berry notes. It is the backbone of Rioja and Ribera del Duero, aging beautifully in American oak.","evolutionLine":[],"regionAffinity":[{"region":"Rioja","bonus":"+1 Focus"}]}'::jsonb),
  ('G012', 'Malbec', 'Originally from Cahors, France, this dark and inky grape has become Argentina''s signature variety. It produces velvety wines with intense plum, blueberry, and cocoa flavors.', 'GRAPES', array['Blueberry', 'Cocoa', 'Plum']::text[], '#800020', 'mountain', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Blueberry","icon":"circle","color":"#483D8B"},{"note":"Cocoa","icon":"cloud","color":"#3E2723"},{"note":"Plum","icon":"droplet","color":"#800080"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Côt","Auxerrois"],"keyRegions":["Mendoza"],"body":"Full-Bodied Red"}'::jsonb, 'COMMON', '{"id":"G012","name":"Malbec","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"France","alternateNames":["Côt","Auxerrois"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blueberry","Cocoa","Plum"],"notableRegions":["Mendoza"],"info":"Originally from Cahors, France, this dark and inky grape has become Argentina''s signature variety. It produces velvety wines with intense plum, blueberry, and cocoa flavors.","evolutionLine":[],"regionAffinity":[{"region":"Mendoza","bonus":"+1 Focus"}]}'::jsonb),
  ('G013', 'Cabernet Franc', 'The parent grape of Cabernet Sauvignon, known for its herbaceous character with bell pepper and raspberry notes. It excels in the Loire Valley and plays a supporting role in Bordeaux blends.', 'GRAPES', array['Bell Pepper', 'Raspberry', 'Graphite']::text[], '#73343A', 'leaf', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Bell Pepper","icon":"triangle","color":"#228B22"},{"note":"Raspberry","icon":"circle","color":"#DC143C"},{"note":"Graphite","icon":"mountain","color":"#708090"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Bouchet","Breton"],"keyRegions":["Loire"],"body":"Medium-Bodied Red"}'::jsonb, 'UNCOMMON', '{"id":"G013","name":"Cabernet Franc","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"France","alternateNames":["Bouchet","Breton"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Bell Pepper","Raspberry","Graphite"],"notableRegions":["Loire"],"info":"The parent grape of Cabernet Sauvignon, known for its herbaceous character with bell pepper and raspberry notes. It excels in the Loire Valley and plays a supporting role in Bordeaux blends.","evolutionLine":[],"regionAffinity":[{"region":"Loire","bonus":"+1 Focus"}]}'::jsonb),
  ('G014', 'Chenin Blanc', 'An incredibly versatile chameleon grape capable of producing dry, sweet, and sparkling wines. Its high acidity allows for exceptional aging and expression of terroir.', 'GRAPES', array['Quince', 'Honey', 'Chamomile']::text[], '#D4B896', 'sun', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Quince","icon":"circle","color":"#DAA520"},{"note":"Honey","icon":"droplet","color":"#FFD700"},{"note":"Chamomile","icon":"sun","color":"#F0E68C"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Steen"],"keyRegions":["Loire"],"body":"Light-Bodied White"}'::jsonb, 'UNCOMMON', '{"id":"G014","name":"Chenin Blanc","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"France","alternateNames":["Steen"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":2,"aromatics":5,"body":2},"tastingProfile":["Quince","Honey","Chamomile"],"notableRegions":["Loire"],"info":"An incredibly versatile chameleon grape capable of producing dry, sweet, and sparkling wines. Its high acidity allows for exceptional aging and expression of terroir.","evolutionLine":[],"regionAffinity":[{"region":"Loire","bonus":"+1 Focus"}]}'::jsonb),
