  ('G016', 'Gamay', 'A fruity and fresh grape that produces light, gulpable wines perfect for serving slightly chilled. It is the sole grape of Beaujolais and excels with carbonic maceration techniques.', 'GRAPES', array['Pomegranate', 'Banana', 'Earth']::text[], '#D4A5A5', 'circle', 'grape', 'grape', 'Light-Bodied Red', '[{"note":"Pomegranate","icon":"circle","color":"#DC143C"},{"note":"Banana","icon":"cloud","color":"#F0E68C"},{"note":"Earth","icon":"mountain","color":"#5D4037"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Gamay Noir"],"keyRegions":["Beaujolais"],"body":"Light-Bodied Red"}'::jsonb, 'UNCOMMON', '{"id":"G016","name":"Gamay","type":"red","style":"Light-Bodied Red","styleId":"light-bodied-red","countryOfOrigin":"France","alternateNames":["Gamay Noir"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":2},"tastingProfile":["Pomegranate","Banana","Earth"],"notableRegions":["Beaujolais"],"info":"A fruity and fresh grape that produces light, gulpable wines perfect for serving slightly chilled. It is the sole grape of Beaujolais and excels with carbonic maceration techniques.","evolutionLine":[],"regionAffinity":[{"region":"Beaujolais","bonus":"+1 Focus"}]}'::jsonb),
  ('G017', 'Zinfandel', 'A bold and jammy grape that produces high-alcohol wines with ripe berry and spice characteristics. Genetically identical to Primitivo, it has become California''s signature red variety.', 'GRAPES', array['Jammy Berry', 'Cinnamon', 'Tobacco']::text[], '#800020', 'flame', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Jammy Berry","icon":"circle","color":"#800080"},{"note":"Cinnamon","icon":"triangle","color":"#D2691E"},{"note":"Tobacco","icon":"cloud","color":"#8B4513"}]'::jsonb, null, null, '{"origin":"Croatia","synonyms":["Primitivo","Tribidrag"],"keyRegions":["California"],"body":"Full-Bodied Red"}'::jsonb, 'COMMON', '{"id":"G017","name":"Zinfandel","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"Croatia","alternateNames":["Primitivo","Tribidrag"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Jammy Berry","Cinnamon","Tobacco"],"notableRegions":["California"],"info":"A bold and jammy grape that produces high-alcohol wines with ripe berry and spice characteristics. Genetically identical to Primitivo, it has become California''s signature red variety.","evolutionLine":[],"regionAffinity":[{"region":"California","bonus":"+1 Focus"}]}'::jsonb),
  ('G018', 'Semillon', 'A golden-hued grape often blended with Sauvignon Blanc, producing waxy whites with lemon curd and lanolin notes. It is essential for Sauternes and ages remarkably well.', 'GRAPES', array['Lemon Curd', 'Beeswax', 'Lanolin']::text[], '#C9A227', 'droplet', 'grape', 'grape', 'Medium-Bodied White', '[{"note":"Lemon Curd","icon":"circle","color":"#FAFAD2"},{"note":"Beeswax","icon":"cloud","color":"#F0E68C"},{"note":"Lanolin","icon":"droplet","color":"#FFFACD"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Sémillon"],"keyRegions":["Bordeaux"],"body":"Medium-Bodied White"}'::jsonb, 'UNCOMMON', '{"id":"G018","name":"Semillon","type":"white","style":"Medium-Bodied White","styleId":"medium-bodied-white","countryOfOrigin":"France","alternateNames":["Sémillon"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":2,"aromatics":5,"body":3},"tastingProfile":["Lemon Curd","Beeswax","Lanolin"],"notableRegions":["Bordeaux"],"info":"A golden-hued grape often blended with Sauvignon Blanc, producing waxy whites with lemon curd and lanolin notes. It is essential for Sauternes and ages remarkably well.","evolutionLine":[],"regionAffinity":[{"region":"Bordeaux","bonus":"+1 Focus"}]}'::jsonb),
  ('G019', 'Mourvèdre', 'A meaty and herbal red grape that produces full-bodied wines with game, black fruit, and herb flavors. It is a key blending partner in GSM blends and the star of Bandol rosé.', 'GRAPES', array['Black Fruit', 'Game', 'Herbs']::text[], '#5D3A1A', 'shield', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Black Fruit","icon":"circle","color":"#2F0F1E"},{"note":"Game","icon":"flame","color":"#8B4513"},{"note":"Herbs","icon":"leaf","color":"#556B2F"}]'::jsonb, null, null, '{"origin":"Spain","synonyms":["Monastrell","Mataro"],"keyRegions":["Rhône"],"body":"Full-Bodied Red"}'::jsonb, 'UNCOMMON', '{"id":"G019","name":"Mourvèdre","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"Spain","alternateNames":["Monastrell","Mataro"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Black Fruit","Game","Herbs"],"notableRegions":["Rhône"],"info":"A meaty and herbal red grape that produces full-bodied wines with game, black fruit, and herb flavors. It is a key blending partner in GSM blends and the star of Bandol rosé.","evolutionLine":[],"regionAffinity":[{"region":"Rhône","bonus":"+1 Focus"}]}'::jsonb),
  ('G020', 'Barbera', 'A juicy and high-acid Italian grape that produces everyday drinking wines with sour cherry and herb flavors. It thrives in Piedmont and offers excellent value.', 'GRAPES', array['Sour Cherry', 'Herbs', 'Liquorice']::text[], '#722F37', 'circle', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Sour Cherry","icon":"circle","color":"#DC143C"},{"note":"Herbs","icon":"leaf","color":"#556B2F"},{"note":"Liquorice","icon":"triangle","color":"#000000"}]'::jsonb, null, null, '{"origin":"Italy","synonyms":[],"keyRegions":["Piedmont"],"body":"Medium-Bodied Red"}'::jsonb, 'COMMON', '{"id":"G020","name":"Barbera","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Italy","alternateNames":[],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Sour Cherry","Herbs","Liquorice"],"notableRegions":["Piedmont"],"info":"A juicy and high-acid Italian grape that produces everyday drinking wines with sour cherry and herb flavors. It thrives in Piedmont and offers excellent value.","evolutionLine":[],"regionAffinity":[{"region":"Piedmont","bonus":"+1 Focus"}]}'::jsonb),
  ('G021', 'Pinot Gris', 'A mutation of Pinot Noir that produces white wines ranging from zesty Italian Pinot Grigio to rich Alsatian styles. Its grayish-pink skin gives it its name.', 'GRAPES', array['Peach', 'Lemon', 'Mineral']::text[], '#D4B896', 'cloud', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Peach","icon":"circle","color":"#FFE4B5"},{"note":"Lemon","icon":"sun","color":"#FFFFE0"},{"note":"Mineral","icon":"mountain","color":"#D3D3D3"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Pinot Grigio","Grauburgunder"],"keyRegions":["Alsace"],"body":"Light-Bodied White"}'::jsonb, 'COMMON', '{"id":"G021","name":"Pinot Gris","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"France","alternateNames":["Pinot Grigio","Grauburgunder"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":2,"aromatics":5,"body":2},"tastingProfile":["Peach","Lemon","Mineral"],"notableRegions":["Alsace"],"info":"A mutation of Pinot Noir that produces white wines ranging from zesty Italian Pinot Grigio to rich Alsatian styles. Its grayish-pink skin gives it its name.","evolutionLine":[],"regionAffinity":[{"region":"Alsace","bonus":"+1 Focus"}]}'::jsonb),
  ('G022', 'Petit Verdot', 'A late-ripening Bordeaux blending grape that adds violet aromas and deep color to wines. Rarely bottled alone, it provides structure and inky depth to the final blend.', 'GRAPES', array['Violet', 'Lilac', 'Sage']::text[], '#800020', 'sparkles', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Violet","icon":"sun","color":"#9370DB"},{"note":"Lilac","icon":"sun","color":"#D8BFD8"},{"note":"Sage","icon":"leaf","color":"#9ACD32"}]'::jsonb, null, null, '{"origin":"France","synonyms":["Verdot"],"keyRegions":["Bordeaux"],"body":"Full-Bodied Red"}'::jsonb, 'RARE', '{"id":"G022","name":"Petit Verdot","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"France","alternateNames":["Verdot"],"rarityTier":"rare","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Violet","Lilac","Sage"],"notableRegions":["Bordeaux"],"info":"A late-ripening Bordeaux blending grape that adds violet aromas and deep color to wines. Rarely bottled alone, it provides structure and inky depth to the final blend.","evolutionLine":[],"regionAffinity":[{"region":"Bordeaux","bonus":"+1 Focus"}]}'::jsonb),
  ('G023', 'Carmenère', 'Once thought extinct in Bordeaux, this lost grape found a new home in Chile where it produces distinctive wines. Its green pepper and raspberry notes make it Chile''s signature variety.', 'GRAPES', array['Green Pepper', 'Raspberry', 'Cocoa']::text[], '#73343A', 'flame', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Green Pepper","icon":"triangle","color":"#556B2F"},{"note":"Raspberry","icon":"droplet","color":"#DC143C"},{"note":"Cocoa","icon":"cloud","color":"#8B4513"}]'::jsonb, null, null, '{"origin":"France","synonyms":[],"keyRegions":["Chile"],"body":"Medium-Bodied Red"}'::jsonb, 'UNCOMMON', '{"id":"G023","name":"Carmenère","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"France","alternateNames":[],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Green Pepper","Raspberry","Cocoa"],"notableRegions":["Chile"],"info":"Once thought extinct in Bordeaux, this lost grape found a new home in Chile where it produces distinctive wines. Its green pepper and raspberry notes make it Chile''s signature variety.","evolutionLine":[],"regionAffinity":[{"region":"Chile","bonus":"+1 Focus"}]}'::jsonb),
