  ('G049', 'Dolcetto', 'A Piedmontese red grape known for juicy black fruit, low acidity, and soft tannins, making it ideal for early drinking. Despite the name meaning ''little sweet one,'' the wines are typically dry and pleasantly bitter on the finish.', 'GRAPES', array['Piedmont', 'Early-Drinking']::text[], '#9B2335', 'circle', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Black Cherry","icon":"circle","color":"#7F1D1D"},{"note":"Violet","icon":"flower","color":"#A78BFA"},{"note":"Almond","icon":"nut","color":"#D6B88D"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium-Low","body":"Medium","tannin":"Medium","keyRegions":["Piedmont"],"synonyms":["Dolcetto di Dogliani"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G049","name":"Dolcetto","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Italy","alternateNames":["Dolcetto di Dogliani"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Black Cherry","Violet","Almond"],"notableRegions":["Piedmont"],"info":"A Piedmontese red grape known for juicy black fruit, low acidity, and soft tannins, making it ideal for early drinking. Despite the name meaning ''little sweet one,'' the wines are typically dry and pleasantly bitter on the finish.","evolutionLine":[],"regionAffinity":[{"region":"Piedmont","bonus":"+1 Focus"}]}'::jsonb),
  ('G050', 'Pinotage', 'South Africa''s signature crossing of Pinot Noir and Cinsault, producing deeply colored wines with dark berry fruit, smoke, and earthy spice. Styles range from fresh and fruit-driven to concentrated, oak-aged bottlings.', 'GRAPES', array['South Africa', 'Bold']::text[], '#5D3A1A', 'flame', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Blackberry","icon":"fruit","color":"#312E81"},{"note":"Smoke","icon":"smoke","color":"#6B7280"},{"note":"Dark Chocolate","icon":"cloud","color":"#4B2E2B"}]'::jsonb, null, null, '{"origin":"South Africa","acidity":"Medium","body":"Full","tannin":"Medium-High","keyRegions":["Stellenbosch","Swartland"],"synonyms":[],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G050","name":"Pinotage","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"South Africa","alternateNames":[],"rarityTier":"uncommon","characteristics":{"tannin":4,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blackberry","Smoke","Dark Chocolate"],"notableRegions":["Stellenbosch","Swartland"],"info":"South Africa''s signature crossing of Pinot Noir and Cinsault, producing deeply colored wines with dark berry fruit, smoke, and earthy spice. Styles range from fresh and fruit-driven to concentrated, oak-aged bottlings.","evolutionLine":[],"regionAffinity":[{"region":"Stellenbosch","bonus":"+1 Focus"},{"region":"Swartland","bonus":"+1 Focus"}]}'::jsonb),
  ('G051', 'Montepulciano', 'A widely planted central Italian red grape that gives plush, fruit-forward wines with moderate tannin and herbal depth. It is the backbone of Montepulciano d''Abruzzo and responds well to both youthful and oak-aged styles.', 'GRAPES', array['Abruzzo', 'Food-Friendly']::text[], '#722F37', 'shield', 'grape', 'grape', 'Medium-Full Red', '[{"note":"Black Plum","icon":"fruit","color":"#581C87"},{"note":"Dried Herbs","icon":"leaf","color":"#4D7C0F"},{"note":"Cocoa","icon":"honey","color":"#5B3A29"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium","body":"Medium-Full","tannin":"Medium","keyRegions":["Abruzzo","Marche"],"synonyms":["Montepulciano d''Abruzzo (grape)"],"classification":"Variety"}'::jsonb, 'COMMON', '{"id":"G051","name":"Montepulciano","type":"red","style":"Medium-Full Red","styleId":"medium-full-red","countryOfOrigin":"Italy","alternateNames":["Montepulciano d''Abruzzo (grape)"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Black Plum","Dried Herbs","Cocoa"],"notableRegions":["Abruzzo","Marche"],"info":"A widely planted central Italian red grape that gives plush, fruit-forward wines with moderate tannin and herbal depth. It is the backbone of Montepulciano d''Abruzzo and responds well to both youthful and oak-aged styles.","evolutionLine":[],"regionAffinity":[{"region":"Abruzzo","bonus":"+1 Focus"},{"region":"Marche","bonus":"+1 Focus"}]}'::jsonb),
  ('G052', 'Corvina', 'The principal red grape of Valpolicella, prized for sour-cherry brightness and herbal lift. Its thick skins and naturally high acidity make it especially suited to appassimento styles like Amarone.', 'GRAPES', array['Veneto', 'Amarone']::text[], '#800020', 'leaf', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Sour Cherry","icon":"circle","color":"#B91C1C"},{"note":"Dried Herbs","icon":"herb","color":"#3F6212"},{"note":"Cinnamon","icon":"spice","color":"#B45309"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"High","body":"Medium","tannin":"Medium-Low","keyRegions":["Valpolicella","Veneto"],"synonyms":["Corvina Veronese"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G052","name":"Corvina","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Italy","alternateNames":["Corvina Veronese"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":4,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Sour Cherry","Dried Herbs","Cinnamon"],"notableRegions":["Valpolicella","Veneto"],"info":"The principal red grape of Valpolicella, prized for sour-cherry brightness and herbal lift. Its thick skins and naturally high acidity make it especially suited to appassimento styles like Amarone.","evolutionLine":[],"regionAffinity":[{"region":"Valpolicella","bonus":"+1 Focus"},{"region":"Veneto","bonus":"+1 Focus"}]}'::jsonb),
  ('G053', 'Rondinella', 'A reliable blending grape from Veneto commonly paired with Corvina in Valpolicella and Amarone. It contributes color, floral aromatics, and steady acidity, especially in dried-grape wines.', 'GRAPES', array['Veneto', 'Blend']::text[], '#73343A', 'droplet', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Red Cherry","icon":"circle","color":"#DC2626"},{"note":"Violet","icon":"flower","color":"#C4B5FD"},{"note":"Dried Fig","icon":"fruit","color":"#7C2D12"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium-High","body":"Medium","tannin":"Low-Medium","keyRegions":["Valpolicella","Veneto"],"synonyms":[],"classification":"Variety"}'::jsonb, 'RARE', '{"id":"G053","name":"Rondinella","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Italy","alternateNames":[],"rarityTier":"rare","characteristics":{"tannin":3,"acid":4,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Red Cherry","Violet","Dried Fig"],"notableRegions":["Valpolicella","Veneto"],"info":"A reliable blending grape from Veneto commonly paired with Corvina in Valpolicella and Amarone. It contributes color, floral aromatics, and steady acidity, especially in dried-grape wines.","evolutionLine":[],"regionAffinity":[{"region":"Valpolicella","bonus":"+1 Focus"},{"region":"Veneto","bonus":"+1 Focus"}]}'::jsonb),
  ('G054', 'Pinot Blanc', 'A white mutation of Pinot Noir producing crisp wines with orchard fruit, almond, and gentle floral notes. It shines in Alsace, Alto Adige, and Germany, where styles range from fresh and linear to richer, lees-aged expressions.', 'GRAPES', array['Alsace', 'Orchard Fruit']::text[], '#D4B896', 'circle', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Green Apple","icon":"circle","color":"#84CC16"},{"note":"Almond","icon":"nut","color":"#D6B88D"},{"note":"White Flower","icon":"flower","color":"#FBCFE8"}]'::jsonb, null, null, '{"origin":"France","acidity":"Medium-High","body":"Light-Medium","tannin":"None","keyRegions":["Alsace","Alto Adige","Germany"],"synonyms":["Pinot Bianco","Weissburgunder"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G054","name":"Pinot Blanc","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"France","alternateNames":["Pinot Bianco","Weissburgunder"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":4,"colorIntensity":2,"aromatics":5,"body":3},"tastingProfile":["Green Apple","Almond","White Flower"],"notableRegions":["Alsace","Alto Adige","Germany"],"info":"A white mutation of Pinot Noir producing crisp wines with orchard fruit, almond, and gentle floral notes. It shines in Alsace, Alto Adige, and Germany, where styles range from fresh and linear to richer, lees-aged expressions.","evolutionLine":[],"regionAffinity":[{"region":"Alsace","bonus":"+1 Focus"},{"region":"Alto Adige","bonus":"+1 Focus"},{"region":"Germany","bonus":"+1 Focus"}]}'::jsonb),
  ('G055', 'Pinot Meunier', 'A key Champagne grape that brings ripe fruit, approachability, and early charm to sparkling blends. As a still wine it can show bright red berry flavors, supple texture, and moderate structure.', 'GRAPES', array['Champagne', 'Sparkling']::text[], '#C48B8B', 'sparkles', 'grape', 'grape', 'Light-Bodied Red', '[{"note":"Red Apple","icon":"circle","color":"#EF4444"},{"note":"Raspberry","icon":"fruit","color":"#E11D48"},{"note":"Brioche","icon":"cloud","color":"#D6B88D"}]'::jsonb, null, null, '{"origin":"France","acidity":"Medium-High","body":"Light-Medium","tannin":"Low","keyRegions":["Champagne","Marlborough"],"synonyms":["Meunier","Schwarzriesling"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G055","name":"Pinot Meunier","type":"red","style":"Light-Bodied Red","styleId":"light-bodied-red","countryOfOrigin":"France","alternateNames":["Meunier","Schwarzriesling"],"rarityTier":"uncommon","characteristics":{"tannin":2,"acid":4,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Red Apple","Raspberry","Brioche"],"notableRegions":["Champagne","Marlborough"],"info":"A key Champagne grape that brings ripe fruit, approachability, and early charm to sparkling blends. As a still wine it can show bright red berry flavors, supple texture, and moderate structure.","evolutionLine":[],"regionAffinity":[{"region":"Champagne","bonus":"+1 Focus"},{"region":"Marlborough","bonus":"+1 Focus"}]}'::jsonb),
  ('G056', 'Petite Sirah', 'A deeply colored, full-bodied red grape known for bold blackberry fruit, pepper, and firm tannins. Widely planted in California, it produces structured wines that can age well with oak integration.', 'GRAPES', array['California', 'High Tannin']::text[], '#722F37', 'shield', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Blackberry","icon":"fruit","color":"#312E81"},{"note":"Black Pepper","icon":"spice","color":"#4B5563"},{"note":"Dark Chocolate","icon":"cloud","color":"#4B2E2B"}]'::jsonb, null, null, '{"origin":"France","acidity":"Medium","body":"Full","tannin":"High","keyRegions":["California","Languedoc"],"synonyms":["Durif"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G056","name":"Petite Sirah","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"France","alternateNames":["Durif"],"rarityTier":"uncommon","characteristics":{"tannin":4,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blackberry","Black Pepper","Dark Chocolate"],"notableRegions":["California","Languedoc"],"info":"A deeply colored, full-bodied red grape known for bold blackberry fruit, pepper, and firm tannins. Widely planted in California, it produces structured wines that can age well with oak integration.","evolutionLine":[],"regionAffinity":[{"region":"California","bonus":"+1 Focus"},{"region":"Languedoc","bonus":"+1 Focus"}]}'::jsonb),
  ('G057', 'Palomino', 'The principal white grape of Jerez, valued for its neutral profile and ability to transmit the effects of biological and oxidative aging in Sherry. In warm climates it yields dry wines with subtle orchard fruit, almond, and saline notes.', 'GRAPES', array['Jerez', 'Sherry']::text[], '#D4B896', 'sun', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Almond","icon":"nut","color":"#D6B88D"},{"note":"Green Apple","icon":"circle","color":"#84CC16"},{"note":"Sea Salt","icon":"mineral","color":"#94A3B8"}]'::jsonb, null, null, '{"origin":"Spain","acidity":"Medium-Low","body":"Light","tannin":"None","keyRegions":["Jerez","Canary Islands"],"synonyms":["Palomino Fino","Listán"],"classification":"Variety"}'::jsonb, 'RARE', '{"id":"G057","name":"Palomino","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"Spain","alternateNames":["Palomino Fino","Listán"],"rarityTier":"rare","characteristics":{"tannin":3,"acid":3,"colorIntensity":2,"aromatics":5,"body":2},"tastingProfile":["Almond","Green Apple","Sea Salt"],"notableRegions":["Jerez","Canary Islands"],"info":"The principal white grape of Jerez, valued for its neutral profile and ability to transmit the effects of biological and oxidative aging in Sherry. In warm climates it yields dry wines with subtle orchard fruit, almond, and saline notes.","evolutionLine":[],"regionAffinity":[{"region":"Jerez","bonus":"+1 Focus"},{"region":"Canary Islands","bonus":"+1 Focus"}]}'::jsonb),
  ('G058', 'Baga', 'Portugal''s structured red grape from Bairrada, producing high-acid, high-tannin wines with dark berries, tobacco, and earthy complexity. It can be rustic in youth but rewards aging and careful extraction.', 'GRAPES', array['Portugal', 'Age-Worthy']::text[], '#800020', 'mountain', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Black Cherry","icon":"circle","color":"#7F1D1D"},{"note":"Tobacco","icon":"leaf","color":"#A16207"},{"note":"Earth","icon":"stone","color":"#57534E"}]'::jsonb, null, null, '{"origin":"Portugal","acidity":"High","body":"Full","tannin":"High","keyRegions":["Bairrada","Dão"],"synonyms":[],"classification":"Variety"}'::jsonb, 'RARE', '{"id":"G058","name":"Baga","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"Portugal","alternateNames":[],"rarityTier":"rare","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Black Cherry","Tobacco","Earth"],"notableRegions":["Bairrada","Dão"],"info":"Portugal''s structured red grape from Bairrada, producing high-acid, high-tannin wines with dark berries, tobacco, and earthy complexity. It can be rustic in youth but rewards aging and careful extraction.","evolutionLine":[],"regionAffinity":[{"region":"Bairrada","bonus":"+1 Focus"},{"region":"Dão","bonus":"+1 Focus"}]}'::jsonb),
  ('G059', 'Teroldego', 'An alpine red from Trentino known for vivid color, dark berry fruit, and firm but polished tannins. It combines mountain freshness with savory spice and often performs well in both stainless and oak-aged styles.', 'GRAPES', array['Trentino', 'Alpine']::text[], '#9B2335', 'mountain', 'grape', 'grape', 'Medium-Full Red', '[{"note":"Blackberry","icon":"fruit","color":"#312E81"},{"note":"Violet","icon":"flower","color":"#A78BFA"},{"note":"Alpine Herbs","icon":"herb","color":"#4D7C0F"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium-High","body":"Medium-Full","tannin":"Medium-High","keyRegions":["Trentino","Alto Adige"],"synonyms":["Teroldego Rotaliano"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G059","name":"Teroldego","type":"red","style":"Medium-Full Red","styleId":"medium-full-red","countryOfOrigin":"Italy","alternateNames":["Teroldego Rotaliano"],"rarityTier":"uncommon","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blackberry","Violet","Alpine Herbs"],"notableRegions":["Trentino","Alto Adige"],"info":"An alpine red from Trentino known for vivid color, dark berry fruit, and firm but polished tannins. It combines mountain freshness with savory spice and often performs well in both stainless and oak-aged styles.","evolutionLine":[],"regionAffinity":[{"region":"Trentino","bonus":"+1 Focus"},{"region":"Alto Adige","bonus":"+1 Focus"}]}'::jsonb),
