  ('G062', 'Melon de Bourgogne', 'The classic grape of Muscadet, delivering lean, saline whites with citrus zest and subtle yeasty notes when aged on lees. Its neutral profile and brisk acidity make it especially seafood-friendly.', 'GRAPES', array['Muscadet', 'Saline']::text[], '#D4B896', 'droplet', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Lemon Zest","icon":"circle","color":"#FACC15"},{"note":"Sea Spray","icon":"mineral","color":"#94A3B8"},{"note":"Brioche","icon":"cloud","color":"#D6B88D"}]'::jsonb, null, null, '{"origin":"France","acidity":"High","body":"Light","tannin":"None","keyRegions":["Loire Valley","Muscadet Sèvre-et-Maine"],"synonyms":["Melon"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G062","name":"Melon de Bourgogne","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"France","alternateNames":["Melon"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":4,"colorIntensity":2,"aromatics":5,"body":2},"tastingProfile":["Lemon Zest","Sea Spray","Brioche"],"notableRegions":["Loire Valley","Muscadet Sèvre-et-Maine"],"info":"The classic grape of Muscadet, delivering lean, saline whites with citrus zest and subtle yeasty notes when aged on lees. Its neutral profile and brisk acidity make it especially seafood-friendly.","evolutionLine":[],"regionAffinity":[{"region":"Loire Valley","bonus":"+1 Focus"},{"region":"Muscadet Sèvre-et-Maine","bonus":"+1 Focus"}]}'::jsonb),
  ('G063', 'Xinomavro', 'Greece''s age-worthy northern red known for high acidity, firm tannins, and aromas of sour cherry, olive, and sun-dried tomato. Often compared stylistically to Nebbiolo for its structure and savory complexity.', 'GRAPES', array['Greece', 'Age-Worthy']::text[], '#800020', 'shield', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Sour Cherry","icon":"circle","color":"#B91C1C"},{"note":"Tomato Leaf","icon":"leaf","color":"#4D7C0F"},{"note":"Olive","icon":"herb","color":"#3F6212"}]'::jsonb, null, null, '{"origin":"Greece","acidity":"High","body":"Full","tannin":"High","keyRegions":["Naoussa","Amyndeon"],"synonyms":[],"classification":"Variety"}'::jsonb, 'RARE', '{"id":"G063","name":"Xinomavro","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"Greece","alternateNames":[],"rarityTier":"rare","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Sour Cherry","Tomato Leaf","Olive"],"notableRegions":["Naoussa","Amyndeon"],"info":"Greece''s age-worthy northern red known for high acidity, firm tannins, and aromas of sour cherry, olive, and sun-dried tomato. Often compared stylistically to Nebbiolo for its structure and savory complexity.","evolutionLine":[],"regionAffinity":[{"region":"Naoussa","bonus":"+1 Focus"},{"region":"Amyndeon","bonus":"+1 Focus"}]}'::jsonb),
  ('G064', 'Agiorgitiko', 'A versatile Greek red from Nemea producing plush wines with red berry fruit, warm spice, and supple tannins. Depending on altitude and élevage, styles range from juicy and youthful to rich and oak-influenced.', 'GRAPES', array['Greece', 'Nemea']::text[], '#73343A', 'flame', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Red Cherry","icon":"circle","color":"#DC2626"},{"note":"Clove","icon":"spice","color":"#B45309"},{"note":"Plum","icon":"fruit","color":"#7E22CE"}]'::jsonb, null, null, '{"origin":"Greece","acidity":"Medium","body":"Medium-Full","tannin":"Medium","keyRegions":["Nemea","Peloponnese"],"synonyms":["St. George"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G064","name":"Agiorgitiko","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Greece","alternateNames":["St. George"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Red Cherry","Clove","Plum"],"notableRegions":["Nemea","Peloponnese"],"info":"A versatile Greek red from Nemea producing plush wines with red berry fruit, warm spice, and supple tannins. Depending on altitude and élevage, styles range from juicy and youthful to rich and oak-influenced.","evolutionLine":[],"regionAffinity":[{"region":"Nemea","bonus":"+1 Focus"},{"region":"Peloponnese","bonus":"+1 Focus"}]}'::jsonb),
  ('G065', 'Glera', 'The principal grape of Prosecco, prized for fresh pear, apple, and white blossom aromas with lively but gentle acidity. It is typically crafted in tank-method sparkling wines that emphasize bright fruit and approachability.', 'GRAPES', array['Prosecco', 'Sparkling']::text[], '#D4B896', 'sparkles', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Pear","icon":"circle","color":"#A3E635"},{"note":"White Peach","icon":"fruit","color":"#FDE68A"},{"note":"White Flower","icon":"flower","color":"#FBCFE8"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium-High","body":"Light","tannin":"None","keyRegions":["Veneto","Friuli-Venezia Giulia"],"synonyms":["Prosecco"],"classification":"Variety"}'::jsonb, 'COMMON', '{"id":"G065","name":"Glera","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"Italy","alternateNames":["Prosecco"],"rarityTier":"common","characteristics":{"tannin":3,"acid":4,"colorIntensity":2,"aromatics":5,"body":2},"tastingProfile":["Pear","White Peach","White Flower"],"notableRegions":["Veneto","Friuli-Venezia Giulia"],"info":"The principal grape of Prosecco, prized for fresh pear, apple, and white blossom aromas with lively but gentle acidity. It is typically crafted in tank-method sparkling wines that emphasize bright fruit and approachability.","evolutionLine":[],"regionAffinity":[{"region":"Veneto","bonus":"+1 Focus"},{"region":"Friuli-Venezia Giulia","bonus":"+1 Focus"}]}'::jsonb),
  ('G066', 'Carignan', 'A Mediterranean red grape known for deep color, savory dark fruit, and naturally high acidity. Old-vine plantings in southern France and Spain can produce concentrated, mineral wines with notable structure.', 'GRAPES', array['Mediterranean', 'Old Vines']::text[], '#800020', 'shield', 'grape', 'grape', 'Medium-Full Red', '[{"note":"Black Cherry","icon":"circle","color":"#7F1D1D"},{"note":"Dried Herbs","icon":"herb","color":"#4D7C0F"},{"note":"Earth","icon":"stone","color":"#57534E"}]'::jsonb, null, null, '{"origin":"Spain","acidity":"High","body":"Medium-Full","tannin":"Medium-High","keyRegions":["Languedoc","Priorat","Sardinia"],"synonyms":["Cariñena","Carignano"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G066","name":"Carignan","type":"red","style":"Medium-Full Red","styleId":"medium-full-red","countryOfOrigin":"Spain","alternateNames":["Cariñena","Carignano"],"rarityTier":"uncommon","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Black Cherry","Dried Herbs","Earth"],"notableRegions":["Languedoc","Priorat","Sardinia"],"info":"A Mediterranean red grape known for deep color, savory dark fruit, and naturally high acidity. Old-vine plantings in southern France and Spain can produce concentrated, mineral wines with notable structure.","evolutionLine":[],"regionAffinity":[{"region":"Languedoc","bonus":"+1 Focus"},{"region":"Priorat","bonus":"+1 Focus"},{"region":"Sardinia","bonus":"+1 Focus"}]}'::jsonb),
