  ('G075', 'Zweigelt', 'Austria''s most planted red grape, combining juicy cherry fruit with peppery spice and bright acidity. It can range from fresh, everyday bottlings to more structured oak-aged versions.', 'GRAPES', array['Austria', 'Juicy']::text[], '#9B2335', 'circle', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Sour Cherry","icon":"circle","color":"#DC2626"},{"note":"Black Pepper","icon":"spice","color":"#4B5563"},{"note":"Violet","icon":"flower","color":"#A78BFA"}]'::jsonb, null, null, '{"origin":"Austria","acidity":"Medium-High","body":"Medium","tannin":"Medium","keyRegions":["Burgenland","Niederösterreich"],"synonyms":["Rotburger"],"classification":"Variety"}'::jsonb, 'COMMON', '{"id":"G075","name":"Zweigelt","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Austria","alternateNames":["Rotburger"],"rarityTier":"common","characteristics":{"tannin":3,"acid":4,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Sour Cherry","Black Pepper","Violet"],"notableRegions":["Burgenland","Niederösterreich"],"info":"Austria''s most planted red grape, combining juicy cherry fruit with peppery spice and bright acidity. It can range from fresh, everyday bottlings to more structured oak-aged versions.","evolutionLine":[],"regionAffinity":[{"region":"Burgenland","bonus":"+1 Focus"},{"region":"Niederösterreich","bonus":"+1 Focus"}]}'::jsonb),
  ('G076', 'Blaufränkisch', 'A central European red grape known for vivid acidity, dark berry fruit, and spicy, mineral edge. It produces energetic wines that can show excellent aging potential in cooler sites.', 'GRAPES', array['Austria', 'Age-Worthy']::text[], '#722F37', 'shield', 'grape', 'grape', 'Medium-Full Red', '[{"note":"Blackberry","icon":"fruit","color":"#312E81"},{"note":"White Pepper","icon":"spice","color":"#E5E7EB"},{"note":"Mineral","icon":"stone","color":"#64748B"}]'::jsonb, null, null, '{"origin":"Austria","acidity":"High","body":"Medium-Full","tannin":"Medium-High","keyRegions":["Burgenland","Mittelburgenland","Hungary"],"synonyms":["Lemberger","Kékfrankos"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G076","name":"Blaufränkisch","type":"red","style":"Medium-Full Red","styleId":"medium-full-red","countryOfOrigin":"Austria","alternateNames":["Lemberger","Kékfrankos"],"rarityTier":"uncommon","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blackberry","White Pepper","Mineral"],"notableRegions":["Burgenland","Mittelburgenland","Hungary"],"info":"A central European red grape known for vivid acidity, dark berry fruit, and spicy, mineral edge. It produces energetic wines that can show excellent aging potential in cooler sites.","evolutionLine":[],"regionAffinity":[{"region":"Burgenland","bonus":"+1 Focus"},{"region":"Mittelburgenland","bonus":"+1 Focus"},{"region":"Hungary","bonus":"+1 Focus"}]}'::jsonb),
  ('G077', 'Nerello Mascalese', 'Sicily''s Etna flagship red, delivering pale color but firm structure with red fruit, herbs, and volcanic minerality. Often compared to Pinot Noir or Nebbiolo for its aromatic lift and tension.', 'GRAPES', array['Etna', 'Volcanic']::text[], '#800020', 'mountain', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Red Cherry","icon":"circle","color":"#DC2626"},{"note":"Dried Herbs","icon":"herb","color":"#4D7C0F"},{"note":"Volcanic Ash","icon":"stone","color":"#6B7280"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"High","body":"Medium","tannin":"Medium-High","keyRegions":["Etna","Sicily"],"synonyms":[],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G077","name":"Nerello Mascalese","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"Italy","alternateNames":[],"rarityTier":"uncommon","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Red Cherry","Dried Herbs","Volcanic Ash"],"notableRegions":["Etna","Sicily"],"info":"Sicily''s Etna flagship red, delivering pale color but firm structure with red fruit, herbs, and volcanic minerality. Often compared to Pinot Noir or Nebbiolo for its aromatic lift and tension.","evolutionLine":[],"regionAffinity":[{"region":"Etna","bonus":"+1 Focus"},{"region":"Sicily","bonus":"+1 Focus"}]}'::jsonb),
  ('G078', 'Primitivo', 'A warm-climate red grape known for ripe black fruit, jammy richness, and generous alcohol. In Puglia it produces plush, spicy wines and shares a genetic identity with Zinfandel.', 'GRAPES', array['Puglia', 'Bold']::text[], '#800020', 'flame', 'grape', 'grape', 'Full-Bodied Red', '[{"note":"Blackberry Jam","icon":"fruit","color":"#4C1D95"},{"note":"Cinnamon","icon":"spice","color":"#B45309"},{"note":"Licorice","icon":"leaf","color":"#1F2937"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium","body":"Full","tannin":"Medium","keyRegions":["Puglia","Manduria"],"synonyms":["Zinfandel","Tribidrag"],"classification":"Variety"}'::jsonb, 'COMMON', '{"id":"G078","name":"Primitivo","type":"red","style":"Full-Bodied Red","styleId":"full-bodied-red","countryOfOrigin":"Italy","alternateNames":["Zinfandel","Tribidrag"],"rarityTier":"common","characteristics":{"tannin":3,"acid":3,"colorIntensity":4,"aromatics":5,"body":5},"tastingProfile":["Blackberry Jam","Cinnamon","Licorice"],"notableRegions":["Puglia","Manduria"],"info":"A warm-climate red grape known for ripe black fruit, jammy richness, and generous alcohol. In Puglia it produces plush, spicy wines and shares a genetic identity with Zinfandel.","evolutionLine":[],"regionAffinity":[{"region":"Puglia","bonus":"+1 Focus"},{"region":"Manduria","bonus":"+1 Focus"}]}'::jsonb),
  ('G079', 'Friulano', 'A northeastern Italian white grape with citrus, almond, and subtle herbal notes, often textured and dry. It is a benchmark variety of Friuli with notable food-pairing versatility.', 'GRAPES', array['Friuli', 'Food-Friendly']::text[], '#D4B896', 'leaf', 'grape', 'grape', 'Light-Bodied White', '[{"note":"Pear","icon":"circle","color":"#A3E635"},{"note":"Almond","icon":"nut","color":"#D6B88D"},{"note":"Herbs","icon":"herb","color":"#4D7C0F"}]'::jsonb, null, null, '{"origin":"Italy","acidity":"Medium","body":"Medium","tannin":"None","keyRegions":["Friuli-Venezia Giulia","Collio"],"synonyms":["Sauvignonasse","Tai"],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G079","name":"Friulano","type":"white","style":"Light-Bodied White","styleId":"light-bodied-white","countryOfOrigin":"Italy","alternateNames":["Sauvignonasse","Tai"],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":3,"colorIntensity":2,"aromatics":5,"body":3},"tastingProfile":["Pear","Almond","Herbs"],"notableRegions":["Friuli-Venezia Giulia","Collio"],"info":"A northeastern Italian white grape with citrus, almond, and subtle herbal notes, often textured and dry. It is a benchmark variety of Friuli with notable food-pairing versatility.","evolutionLine":[],"regionAffinity":[{"region":"Friuli-Venezia Giulia","bonus":"+1 Focus"},{"region":"Collio","bonus":"+1 Focus"}]}'::jsonb),
  ('G080', 'Fer Servadou', 'A southwest French red grape valued for brisk acidity, black fruit, and peppery herbal character. It adds structure and freshness in blends and can produce savory, medium-bodied varietal wines.', 'GRAPES', array['Southwest France', 'Savory']::text[], '#73343A', 'shield', 'grape', 'grape', 'Medium-Bodied Red', '[{"note":"Blackcurrant","icon":"fruit","color":"#312E81"},{"note":"Green Peppercorn","icon":"spice","color":"#4D7C0F"},{"note":"Violet","icon":"flower","color":"#A78BFA"}]'::jsonb, null, null, '{"origin":"France","acidity":"High","body":"Medium","tannin":"Medium-High","keyRegions":["Gaillac","Marcillac"],"synonyms":["Braucol","Mansois"],"classification":"Variety"}'::jsonb, 'RARE', '{"id":"G080","name":"Fer Servadou","type":"red","style":"Medium-Bodied Red","styleId":"medium-bodied-red","countryOfOrigin":"France","alternateNames":["Braucol","Mansois"],"rarityTier":"rare","characteristics":{"tannin":4,"acid":4,"colorIntensity":4,"aromatics":5,"body":3},"tastingProfile":["Blackcurrant","Green Peppercorn","Violet"],"notableRegions":["Gaillac","Marcillac"],"info":"A southwest French red grape valued for brisk acidity, black fruit, and peppery herbal character. It adds structure and freshness in blends and can produce savory, medium-bodied varietal wines.","evolutionLine":[],"regionAffinity":[{"region":"Gaillac","bonus":"+1 Focus"},{"region":"Marcillac","bonus":"+1 Focus"}]}'::jsonb),
  ('G081', 'Moschofilero', 'An aromatic Greek pink-skinned grape used for fragrant white wines with rose, citrus, and spice notes. It is especially associated with high-altitude Mantinia styles marked by freshness and perfume.', 'GRAPES', array['Greece', 'Aromatic']::text[], '#C48B8B', 'sparkles', 'grape', 'grape', 'Aromatic White', '[{"note":"Rose Petal","icon":"flower","color":"#F9A8D4"},{"note":"Lemon","icon":"circle","color":"#FACC15"},{"note":"Ginger","icon":"spice","color":"#B45309"}]'::jsonb, null, null, '{"origin":"Greece","acidity":"High","body":"Light","tannin":"None","keyRegions":["Mantinia","Peloponnese"],"synonyms":[],"classification":"Variety"}'::jsonb, 'UNCOMMON', '{"id":"G081","name":"Moschofilero","type":"white","style":"Aromatic White","styleId":"aromatic-white","countryOfOrigin":"Greece","alternateNames":[],"rarityTier":"uncommon","characteristics":{"tannin":3,"acid":4,"colorIntensity":2,"aromatics":5,"body":2},"tastingProfile":["Rose Petal","Lemon","Ginger"],"notableRegions":["Mantinia","Peloponnese"],"info":"An aromatic Greek pink-skinned grape used for fragrant white wines with rose, citrus, and spice notes. It is especially associated with high-altitude Mantinia styles marked by freshness and perfume.","evolutionLine":[],"regionAffinity":[{"region":"Mantinia","bonus":"+1 Focus"},{"region":"Peloponnese","bonus":"+1 Focus"}]}'::jsonb),
  ('R001', 'Bordeaux', 'The world''s most famous wine region, renowned for its prestigious blends of Cabernet Sauvignon and Merlot. Its classification system and château culture have set the standard for fine wine globally.', 'REGIONS', array['France', 'Blends']::text[], '#722F37', 'mountain', 'region', 'region', null, '[]'::jsonb, 'maritime', 'Atlantic influence moderates growing seasons.', '{"origin":"France","notableGrapes":["Cabernet Sauvignon","Merlot","Cabernet Franc"],"classification":"AOC","appellations":["Pauillac","Margaux","Saint-Julien","Saint-Émilion","Pomerol","Pessac-Léognan","Sauternes"]}'::jsonb, null, null),
  ('R002', 'Burgundy', 'The spiritual home of Pinot Noir and Chardonnay, where terroir is expressed with unmatched precision. Its complex hierarchy of vineyards spans from regional wines to legendary Grand Crus.', 'REGIONS', array['France', 'Terroir']::text[], '#9B2335', 'mountain', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"France","notableGrapes":["Pinot Noir","Chardonnay"],"classification":"AOC","appellations":["Gevrey-Chambertin","Vosne-Romanée","Meursault","Puligny-Montrachet","Nuits-Saint-Georges","Pommard"]}'::jsonb, null, null),
  ('R003', 'Champagne', 'The only region that can legally produce true Champagne, using the traditional method of secondary fermentation in bottle. Its chalky soils and cool climate create wines of exceptional finesse and elegance.', 'REGIONS', array['France', 'Sparkling']::text[], '#D4B896', 'sparkles', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"France","notableGrapes":["Chardonnay","Pinot Noir","Pinot Meunier"],"classification":"AOC","appellations":["Montagne de Reims","Côte des Blancs","Vallée de la Marne"]}'::jsonb, null, null),
  ('R004', 'Rhône Valley', 'A sun-drenched region divided into the elegant Northern Rhône and the broader Southern Rhône. It produces powerful Syrahs in the north and rich GSM blends in the south.', 'REGIONS', array['France', 'Syrah']::text[], '#800020', 'flame', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"France","notableGrapes":["Syrah","Grenache","Mourvèdre"],"classification":"AOC","appellations":["Hermitage","Côte-Rôtie","Châteauneuf-du-Pape","Gigondas","Crozes-Hermitage"]}'::jsonb, null, null),
  ('R005', 'Loire Valley', 'Known as the Garden of France, this diverse region stretches along the Loire River. It produces everything from crisp Sauvignon Blanc to age-worthy Chenin Blanc and elegant Cabernet Franc.', 'REGIONS', array['France', 'Diverse']::text[], '#D4B896', 'leaf', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"France","notableGrapes":["Chenin Blanc","Sauvignon Blanc","Cabernet Franc"],"classification":"AOC","appellations":["Sancerre","Vouvray","Muscadet","Chinon","Savennières"]}'::jsonb, null, null),
  ('R006', 'Alsace', 'A unique French region with Germanic influence, known for its aromatic white wines in distinctive tall bottles. The dry Rieslings and spicy Gewürztraminers are among France''s finest whites.', 'REGIONS', array['France', 'Aromatic']::text[], '#C9A227', 'triangle', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"France","notableGrapes":["Riesling","Gewürztraminer","Pinot Gris"],"classification":"AOC","appellations":["Alsace Grand Cru"]}'::jsonb, null, null),
  ('R007', 'Provence', 'The world''s most famous rosé-producing region, blessed with Mediterranean sunshine and maritime breezes. Its pale, dry rosés have become synonymous with summer elegance.', 'REGIONS', array['France', 'Rosé']::text[], '#C48B8B', 'sun', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"France","notableGrapes":["Grenache","Cinsault","Mourvèdre"],"classification":"AOC","appellations":["Bandol","Côtes de Provence","Cassis"]}'::jsonb, null, null),
  ('R008', 'Beaujolais', 'The home of Gamay grape, producing bright, fruity wines that range from simple Nouveau to age-worthy Cru wines. Its ten crus showcase the diversity possible from a single grape variety.', 'REGIONS', array['France', 'Gamay']::text[], '#D4A5A5', 'circle', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"France","notableGrapes":["Gamay"],"classification":"AOC","appellations":["Morgon","Fleurie","Moulin-à-Vent","Brouilly","Côte de Brouilly","Chiroubles","Saint-Amour","Juliénas","Chénas","Régnié"]}'::jsonb, null, null),
  ('R009', 'Languedoc', 'France''s largest wine region, offering exceptional value and increasingly high quality wines. Once known for bulk wine, it now produces exciting reds from Mediterranean varieties.', 'REGIONS', array['France', 'Value']::text[], '#800020', 'sun', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"France","notableGrapes":["Carignan","Grenache","Syrah"],"classification":"AOC"}'::jsonb, null, null),
  ('R010', 'Chablis', 'A northern outpost of Burgundy famous for mineral, unoaked Chardonnay that expresses pure chalky terroir. Its Grand Crus and Premier Crus are among the world''s greatest white wines.', 'REGIONS', array['France', 'Mineral']::text[], '#D4B896', 'mountain', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"France","notableGrapes":["Chardonnay"],"classification":"AOC","appellations":["Chablis Grand Cru","Chablis Premier Cru"]}'::jsonb, null, null),
  ('R011', 'Sauternes', 'The world''s most celebrated sweet wine region, where noble rot transforms Sémillon and Sauvignon Blanc into liquid gold. Château d''Yquem leads this prestigious appellation.', 'REGIONS', array['France', 'Sweet']::text[], '#C9A227', 'sparkles', 'region', 'region', null, '[]'::jsonb, 'maritime', null, '{"origin":"France","notableGrapes":["Sémillon","Sauvignon Blanc"],"classification":"AOC"}'::jsonb, null, null),
  ('R012', 'Jura', 'A quirky French region known for its unique oxidative wines like Vin Jaune and distinctive local grapes. Its Savagnin and Poulsard wines offer flavors found nowhere else.', 'REGIONS', array['France', 'Unique']::text[], '#C67530', 'triangle', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"France","notableGrapes":["Savagnin","Poulsard","Trousseau"],"classification":"AOC"}'::jsonb, null, null),
  ('R013', 'Napa Valley', 'America''s most prestigious wine region, known for powerful Cabernet Sauvignon that rivals Bordeaux. Its combination of climate, terroir, and investment has created world-class wines.', 'REGIONS', array['USA', 'Cabernet']::text[], '#722F37', 'mountain', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"USA","notableGrapes":["Cabernet Sauvignon","Chardonnay","Merlot"],"classification":"AVA","appellations":["Oakville","Rutherford","Stags Leap District","Howell Mountain","St. Helena"]}'::jsonb, null, null),
  ('R014', 'Sonoma', 'Napa''s diverse coastal neighbor, producing excellent wines from numerous varieties across varied microclimates. Its cooler sites excel with Pinot Noir and Chardonnay.', 'REGIONS', array['USA', 'Diverse']::text[], '#9B2335', 'leaf', 'region', 'region', null, '[]'::jsonb, 'maritime', 'Pacific fog and breezes temper ripening.', '{"origin":"USA","notableGrapes":["Pinot Noir","Chardonnay","Zinfandel"],"classification":"AVA","appellations":["Russian River Valley","Sonoma Coast","Alexander Valley","Dry Creek Valley"]}'::jsonb, null, null),
  ('R015', 'Willamette Valley', 'Oregon''s cool-climate paradise for Pinot Noir, producing elegant wines that rival Burgundy. Its diverse soil types and microclimates create wines of remarkable complexity.', 'REGIONS', array['USA', 'Pinot Noir']::text[], '#C48B8B', 'leaf', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"USA","notableGrapes":["Pinot Noir","Pinot Gris","Chardonnay"],"classification":"AVA","appellations":["Dundee Hills","Eola-Amity Hills","Chehalem Mountains"]}'::jsonb, null, null),
  ('R016', 'Paso Robles', 'California''s hub for Rhône varieties, producing bold Syrahs and GSM blends in a warm, inland climate. Its limestone soils add complexity to powerful, ripe wines.', 'REGIONS', array['USA', 'Rhône']::text[], '#800020', 'flame', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"USA","notableGrapes":["Syrah","Grenache","Mourvèdre"],"classification":"AVA"}'::jsonb, null, null),
  ('R017', 'Walla Walla', 'Washington State''s premium wine valley, known for elegant Syrah and refined Cabernet Sauvignon. Its high desert climate produces wines of intense flavor and balance.', 'REGIONS', array['USA', 'Syrah']::text[], '#73343A', 'mountain', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"USA","notableGrapes":["Syrah","Cabernet Sauvignon","Merlot"],"classification":"AVA"}'::jsonb, null, null),
  ('R018', 'Santa Barbara', 'Cool-climate California wine country made famous by the film Sideways. Its transverse valleys channel ocean fog to create ideal conditions for Pinot Noir and Chardonnay.', 'REGIONS', array['USA', 'Cool Climate']::text[], '#C48B8B', 'sun', 'region', 'region', null, '[]'::jsonb, 'cool', 'Ocean-cooled valleys with strong diurnal shift.', '{"origin":"USA","notableGrapes":["Pinot Noir","Chardonnay","Syrah"],"classification":"AVA","appellations":["Sta. Rita Hills","Santa Maria Valley","Happy Canyon"]}'::jsonb, null, null),
  ('R019', 'Finger Lakes', 'New York State''s premier wine region, producing world-class Riesling from steep lakeside vineyards. The deep lakes moderate the harsh climate to allow viticulture.', 'REGIONS', array['USA', 'Riesling']::text[], '#C9A227', 'droplet', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"USA","notableGrapes":["Riesling","Cabernet Franc"],"classification":"AVA"}'::jsonb, null, null),
  ('R020', 'Lodi', 'California''s treasure trove of old vine Zinfandel, some over 100 years old. These ancient vines produce concentrated, complex wines at excellent value.', 'REGIONS', array['USA', 'Zinfandel']::text[], '#800020', 'flame', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"USA","notableGrapes":["Zinfandel"],"classification":"AVA"}'::jsonb, null, null),
  ('R021', 'Tuscany', 'Italy''s most beloved wine region, where Sangiovese reigns supreme across varied terroirs. From Chianti to Brunello to Super Tuscans, it offers incredible diversity.', 'REGIONS', array['Italy', 'Sangiovese']::text[], '#9B2335', 'sun', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Italy","notableGrapes":["Sangiovese","Cabernet Sauvignon"],"classification":"DOCG","appellations":["Chianti Classico","Brunello di Montalcino","Vino Nobile di Montepulciano","Bolgheri"]}'::jsonb, null, null),
  ('R022', 'Piedmont', 'The home of Nebbiolo, producing Italy''s greatest red wines including Barolo and Barbaresco. Its fog-shrouded hills also yield excellent Barbera and Moscato.', 'REGIONS', array['Italy', 'Nebbiolo']::text[], '#9B2335', 'mountain', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Italy","notableGrapes":["Nebbiolo","Barbera","Moscato"],"classification":"DOCG","appellations":["Barolo","Barbaresco","Barbera d''Asti","Moscato d''Asti","Gavi","Roero"]}'::jsonb, null, null),
  ('R023', 'Veneto', 'Italy''s most productive wine region, home to Prosecco, Amarone, and Soave. Its diverse wines range from light sparklers to powerful dried-grape reds.', 'REGIONS', array['Italy', 'Diverse']::text[], '#D4B896', 'sparkles', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Italy","notableGrapes":["Corvina","Glera","Garganega"],"classification":"DOC","appellations":["Valpolicella","Soave","Prosecco","Amarone della Valpolicella"]}'::jsonb, null, null),
  ('R024', 'Sicily', 'Italy''s largest wine island, producing increasingly impressive wines from ancient native varieties. Volcanic Mount Etna has become a hotbed for elegant reds and mineral whites.', 'REGIONS', array['Italy', 'Island']::text[], '#800020', 'sun', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Italy","notableGrapes":["Nero d''Avola","Grillo","Nerello Mascalese"],"classification":"DOC","appellations":["Etna","Cerasuolo di Vittoria"]}'::jsonb, null, null),
  ('R025', 'Campania', 'Southern Italy''s jewel of ancient grape varieties grown on volcanic soils near Naples. Aglianico produces powerful reds while Fiano and Greco make distinctive whites.', 'REGIONS', array['Italy', 'Volcanic']::text[], '#5D3A1A', 'flame', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Italy","notableGrapes":["Aglianico","Fiano","Greco"],"classification":"DOC","appellations":["Taurasi","Fiano di Avellino","Greco di Tufo"]}'::jsonb, null, null),
  ('R026', 'Friuli-Venezia Giulia', 'Italy''s top region for premium white wines, bordering Slovenia and Austria. Its mineral-driven Friulano and aromatic Ribolla Gialla showcase northeastern elegance.', 'REGIONS', array['Italy', 'White']::text[], '#D4B896', 'sun', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"Italy","notableGrapes":["Friulano","Pinot Grigio","Ribolla Gialla"],"classification":"DOC","appellations":["Collio","Colli Orientali del Friuli"]}'::jsonb, null, null),
  ('R027', 'Alto Adige', 'A bilingual Italian-German region in the Alps producing fresh, aromatic white wines. Its steep mountain vineyards yield distinctive Pinot Grigio and Gewürztraminer.', 'REGIONS', array['Italy', 'Alpine']::text[], '#D4B896', 'mountain', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"Italy","notableGrapes":["Pinot Grigio","Gewürztraminer","Lagrein"],"classification":"DOC"}'::jsonb, null, null),
  ('R028', 'Abruzzo', 'Central Italy''s workhorse region, famous for value-driven Montepulciano d''Abruzzo. Its rustic, fruity reds offer excellent quality at accessible prices.', 'REGIONS', array['Italy', 'Value']::text[], '#722F37', 'mountain', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Italy","notableGrapes":["Montepulciano"],"classification":"DOC"}'::jsonb, null, null),
  ('R029', 'Puglia', 'The heel of Italy''s boot, producing bold, fruity reds from Primitivo and Negroamaro. Once a source of blending wine, it now bottles excellent value wines.', 'REGIONS', array['Italy', 'Southern']::text[], '#800020', 'sun', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Italy","notableGrapes":["Primitivo","Negroamaro"],"classification":"DOC"}'::jsonb, null, null),
  ('R030', 'Rioja', 'Spain''s most famous wine region, known for Tempranillo-based wines aged in American oak. Its traditional wines offer vanilla and coconut notes alongside red fruit.', 'REGIONS', array['Spain', 'Tempranillo']::text[], '#800020', 'shield', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Spain","notableGrapes":["Tempranillo","Garnacha","Graciano"],"classification":"DOCa"}'::jsonb, null, null),
  ('R031', 'Ribera del Duero', 'High-altitude wine country producing powerful, concentrated Tempranillo wines. Its extreme climate creates bold wines with intense fruit and firm structure.', 'REGIONS', array['Spain', 'Bold']::text[], '#722F37', 'mountain', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Spain","notableGrapes":["Tempranillo"],"classification":"DO"}'::jsonb, null, null),
  ('R032', 'Priorat', 'A dramatic region of ancient slate soils producing intensely concentrated wines. Its Garnacha and Cariñena vines struggle in poor soil to yield powerful, mineral wines.', 'REGIONS', array['Spain', 'Intense']::text[], '#5D3A1A', 'mountain', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Spain","notableGrapes":["Grenache","Carignan"],"classification":"DOCa"}'::jsonb, null, null),
  ('R033', 'Rías Baixas', 'Spain''s premier white wine region on the Atlantic coast of Galicia. Its Albariño wines show distinctive salinity and freshness from the maritime influence.', 'REGIONS', array['Spain', 'Albariño']::text[], '#D4B896', 'droplet', 'region', 'region', null, '[]'::jsonb, 'maritime', null, '{"origin":"Spain","notableGrapes":["Albariño"],"classification":"DO"}'::jsonb, null, null),
