  ('R046', 'Maipo Valley', 'Chile''s most prestigious wine valley, known for powerful Cabernet Sauvignon. Its proximity to Santiago and excellent terroir make it Chile''s wine showcase.', 'REGIONS', array['Chile', 'Cabernet']::text[], '#722F37', 'mountain', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"Chile","notableGrapes":["Cabernet Sauvignon","Carmenère"],"classification":"DO"}'::jsonb, null, null),
  ('R047', 'Stellenbosch', 'South Africa''s premier wine region, producing world-class Cabernet Sauvignon and unique Pinotage. Its mountain slopes and varied soils create wines of great diversity.', 'REGIONS', array['South Africa', 'Cabernet']::text[], '#722F37', 'mountain', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"South Africa","notableGrapes":["Cabernet Sauvignon","Pinotage","Chenin Blanc"],"classification":"WO"}'::jsonb, null, null),
  ('R048', 'Santorini', 'A Greek island of volcanic vineyards producing intensely mineral Assyrtiko. Its ancient vines are trained in basket shapes to protect against fierce winds.', 'REGIONS', array['Greece', 'Volcanic']::text[], '#D4B896', 'mountain', 'region', 'region', null, '[]'::jsonb, 'mediterranean', null, '{"origin":"Greece","notableGrapes":["Assyrtiko"],"classification":"PDO"}'::jsonb, null, null),
  ('R049', 'Tokaj', 'Hungary''s legendary region producing Tokaji Aszú, one of the world''s great sweet wines. Its botrytis-affected Furmint grapes create wines of extraordinary complexity.', 'REGIONS', array['Hungary', 'Sweet']::text[], '#C9A227', 'sparkles', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Hungary","notableGrapes":["Furmint","Hárslevelű"],"classification":"DHC"}'::jsonb, null, null),
