  ('R051', 'Shangri-La', 'Sky-high vineyards perched along the Mekong in Yunnan, delivering perfumed reds with alpine freshness from ancient terraces.', 'REGIONS', array['China', 'High Altitude']::text[], '#9B2335', 'mountain', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"China","notableGrapes":["Cabernet Sauvignon","Syrah"],"classification":"GI","soilType":"Alluvial, slate"}'::jsonb, null, null),
