  ('R055', 'Swartland', 'Swartland''s old bush vines and granite soils craft textured Chenin Blanc and soulful Rhône-style reds with minimal intervention.', 'REGIONS', array['South Africa', 'Chenin']::text[], '#5D3A1A', 'flame', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"South Africa","notableGrapes":["Chenin Blanc","Syrah","Grenache"],"classification":"WO","soilType":"Granite, shale"}'::jsonb, null, null),
  ('R056', 'Walker Bay', 'A cool, ocean-swept corner famed for Hemel-en-Aarde Pinot Noir and Chardonnay, delivering Burgundian elegance with South African sunshine.', 'REGIONS', array['South Africa', 'Cool Climate']::text[], '#C48B8B', 'droplet', 'region', 'region', null, '[]'::jsonb, 'cool', null, '{"origin":"South Africa","notableGrapes":["Pinot Noir","Chardonnay"],"classification":"WO","soilType":"Clay, shale"}'::jsonb, null, null),
  ('R057', 'Paarl & Franschhoek', 'Historic valleys east of Stellenbosch producing rich reds, fynbos-scented whites, and South Africa''s marquee Cap Classique sparklers.', 'REGIONS', array['South Africa', 'Cap Classique']::text[], '#722F37', 'sparkles', 'region', 'region', null, '[]'::jsonb, 'warm', null, '{"origin":"South Africa","notableGrapes":["Cabernet Sauvignon","Chenin Blanc","Pinotage"],"classification":"WO","soilType":"Granite, sandstone"}'::jsonb, null, null),
  ('R058', 'Kakheti', 'Georgia''s eastern cradle of wine, famous for skin-contact amber wines and powerful Saperavi reds fermented in buried qvevri.', 'REGIONS', array['Georgia', 'Qvevri']::text[], '#C67530', 'sun', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Georgia","notableGrapes":["Saperavi","Rkatsiteli","Kisi"],"classification":"PDO","soilType":"Alluvial, clay"}'::jsonb, null, null),
  ('R059', 'Kartli', 'Highland vineyards near Tbilisi yielding elegant sparkling Chinuri and balanced qvevri whites with alpine freshness.', 'REGIONS', array['Georgia', 'Highland']::text[], '#D4B896', 'sparkles', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Georgia","notableGrapes":["Chinuri","Goruli Mtsvane"],"classification":"PDO","soilType":"Limestone, clay"}'::jsonb, null, null),
  ('R060', 'Imereti', 'Western Georgia''s humid hills where partial qvevri fermentations craft brighter, mineral-driven amber and red wines.', 'REGIONS', array['Georgia', 'Mineral']::text[], '#C9A227', 'leaf', 'region', 'region', null, '[]'::jsonb, 'continental', null, '{"origin":"Georgia","notableGrapes":["Tsolikouri","Otskhanuri Sapere"],"classification":"PDO","soilType":"Clay, sandstone"}'::jsonb, null, null),
  ('S001', 'Full-Bodied Red', 'Rich, tannic wines with intense dark fruit flavors that command attention on the palate. These powerful wines typically benefit from aging and pair beautifully with hearty red meats.', 'STYLES', array['Bold', 'Tannic']::text[], '#722F37', 'flame', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Full","tannin":"High","keyRegions":["Bordeaux","Napa","Barossa"],"notableGrapes":["Cabernet Sauvignon","Syrah","Malbec","Nebbiolo"],"classification":"STYLE"}'::jsonb, null, null),
  ('S002', 'Light-Bodied Red', 'Delicate, elegant reds with bright acidity and fresh red fruit character that are perfect for lighter fare. These subtle wines showcase finesse over power and can even be served slightly chilled.', 'STYLES', array['Light', 'Fresh']::text[], '#C48B8B', 'droplet', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Light","tannin":"Low","keyRegions":["Burgundy","Oregon","Loire"],"notableGrapes":["Pinot Noir","Gamay","Cinsault"],"classification":"STYLE"}'::jsonb, null, null),
  ('S003', 'Medium-Bodied Red', 'Versatile reds that balance fruit, structure, and elegance for everyday enjoyment. These food-friendly wines bridge the gap between light and bold styles.', 'STYLES', array['Balanced', 'Versatile']::text[], '#9B2335', 'circle', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Medium","tannin":"Medium","keyRegions":["Rioja","Tuscany","Rhône"],"notableGrapes":["Sangiovese","Tempranillo","Merlot","Grenache"],"classification":"STYLE"}'::jsonb, null, null),
  ('S004', 'Full-Bodied White', 'Opulent white wines often with oak influence, offering rich texture and creamy mouthfeel. These wines pair wonderfully with rich seafood, poultry, and cream-based dishes.', 'STYLES', array['Rich', 'Oaked']::text[], '#C9A227', 'sun', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Full","tannin":"None","keyRegions":["Burgundy","Napa","Rhône"],"notableGrapes":["Chardonnay","Viognier","Roussanne","Marsanne"],"classification":"STYLE"}'::jsonb, null, null),
  ('S005', 'Light-Bodied White', 'Crisp, refreshing whites with high acidity and clean, mineral-driven flavors. These thirst-quenching wines are perfect aperitifs or paired with light seafood.', 'STYLES', array['Crisp', 'Refreshing']::text[], '#D4B896', 'droplet', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Light","acidity":"High","keyRegions":["Loire","Marlborough","Alto Adige"],"notableGrapes":["Sauvignon Blanc","Pinot Grigio","Muscadet","Albariño"],"classification":"STYLE"}'::jsonb, null, null),
  ('S006', 'Aromatic White', 'Intensely fragrant white wines with floral, fruity, and spicy aromas that leap from the glass. These expressive wines often have a touch of residual sugar to balance their bold aromatics.', 'STYLES', array['Aromatic', 'Floral']::text[], '#C9A227', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Light-Medium","acidity":"Medium","keyRegions":["Alsace","Germany","Austria"],"notableGrapes":["Riesling","Gewürztraminer","Torrontés","Moscato"],"classification":"STYLE"}'::jsonb, null, null),
  ('S007', 'Rosé', 'Refreshing pink wines made from red grapes with minimal skin contact. These versatile, food-friendly wines range from bone-dry to slightly sweet.', 'STYLES', array['Pink', 'Summer']::text[], '#C48B8B', 'sun', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Light-Medium","acidity":"High","keyRegions":["Provence","Spain","California"],"notableGrapes":["Grenache","Cinsault","Mourvèdre","Sangiovese"],"classification":"STYLE"}'::jsonb, null, null),
  ('S008', 'Sparkling Wine', 'Effervescent wines with elegant bubbles created through secondary fermentation. From simple Prosecco to prestigious Champagne, bubbles add celebration to any occasion.', 'STYLES', array['Bubbles', 'Celebration']::text[], '#D4B896', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Light","acidity":"High","keyRegions":["Champagne","Prosecco","Cava"],"notableGrapes":["Chardonnay","Pinot Noir","Glera","Pinot Meunier"],"classification":"STYLE"}'::jsonb, null, null),
  ('S009', 'Champagne', 'The original and most prestigious sparkling wine, made only in the Champagne region of France. Its traditional method production creates unmatched finesse and complexity.', 'STYLES', array['Prestige', 'Traditional']::text[], '#D4B896', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"France","body":"Light-Medium","acidity":"High","keyRegions":["Champagne"],"notableGrapes":["Chardonnay","Pinot Noir","Pinot Meunier"],"classification":"STYLE"}'::jsonb, null, null),
  ('S010', 'Dessert Wine', 'Lusciously sweet wines crafted from super-ripe or dried grapes, perfect for ending a meal. These concentrated wines balance intense sweetness with vibrant acidity.', 'STYLES', array['Sweet', 'Dessert']::text[], '#C9A227', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Full","acidity":"High","keyRegions":["Sauternes","Tokaj","Germany"],"notableGrapes":["Sémillon","Riesling","Furmint","Chenin Blanc"],"classification":"STYLE"}'::jsonb, null, null),
  ('S011', 'Fortified Wine', 'Wines strengthened with grape spirit to increase alcohol and preserve sweetness. From dry Sherry to sweet Port, these complex wines offer remarkable longevity.', 'STYLES', array['Fortified', 'Strong']::text[], '#C67530', 'flame', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Full","tannin":"Varies","keyRegions":["Porto","Jerez","Madeira"],"notableGrapes":["Touriga Nacional","Palomino","Tinta Roriz"],"classification":"STYLE"}'::jsonb, null, null),
  ('S012', 'Port', 'Portugal''s famous sweet fortified wine from the Douro Valley, made by adding brandy during fermentation. Its rich, concentrated flavors range from fruity Ruby to aged Tawny styles.', 'STYLES', array['Sweet', 'Fortified']::text[], '#5D3A1A', 'flame', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Portugal","body":"Full","tannin":"High","keyRegions":["Douro"],"notableGrapes":["Touriga Nacional","Touriga Franca","Tinta Roriz"],"classification":"STYLE"}'::jsonb, null, null),
  ('S013', 'Sherry', 'Spain''s unique fortified wine from Jerez, aged in a solera system to create complex oxidative or biological styles. From dry Fino to sweet Pedro Ximénez, it offers incredible diversity.', 'STYLES', array['Oxidative', 'Nutty']::text[], '#C67530', 'sun', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Spain","body":"Varies","acidity":"High","keyRegions":["Jerez"],"notableGrapes":["Palomino","Pedro Ximénez"],"classification":"STYLE"}'::jsonb, null, null),
  ('S014', 'Natural Wine', 'Low-intervention wines made with minimal additives and often without filtration. These authentic wines showcase the true expression of grape and terroir.', 'STYLES', array['Natural', 'Organic']::text[], '#C67530', 'leaf', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Varies","acidity":"Varies","keyRegions":["Jura","Loire","Georgia"],"notableGrapes":["Savagnin","Chenin Blanc","Cabernet Franc"],"classification":"STYLE"}'::jsonb, null, null),
  ('S015', 'Orange Wine', 'White grapes vinified like red wine, with extended skin contact creating amber color and tannic structure. This ancient technique produces textural, complex wines.', 'STYLES', array['Skin Contact', 'Textural']::text[], '#C67530', 'sun', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Medium-Full","tannin":"Low-Medium","keyRegions":["Georgia","Friuli","Slovenia"],"notableGrapes":["Ribolla Gialla","Pinot Grigio","Rkatsiteli"],"classification":"STYLE"}'::jsonb, null, null),
  ('S016', 'Pétillant Naturel', 'Naturally sparkling wines made using the ancestral method, bottled before primary fermentation completes. These rustic, cloudy sparklers offer fresh, unpredictable character.', 'STYLES', array['Natural', 'Fizzy']::text[], '#D4A5A5', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Light","acidity":"High","keyRegions":["Loire","Various"],"notableGrapes":["Chenin Blanc","Gamay","Various"],"classification":"STYLE"}'::jsonb, null, null),
  ('S017', 'Late Harvest', 'Sweet wines made from grapes left on the vine past normal harvest to concentrate sugar. This simple technique creates rich, fruity dessert wines without noble rot.', 'STYLES', array['Sweet', 'Ripe']::text[], '#C9A227', 'sun', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Medium-Full","acidity":"Medium","keyRegions":["Germany","Alsace","California"],"notableGrapes":["Riesling","Gewürztraminer","Sémillon"],"classification":"STYLE"}'::jsonb, null, null),
  ('S018', 'Ice Wine', 'Ultra-sweet wines made from grapes naturally frozen on the vine, concentrating sugars and acids. These rare, expensive wines require specific climate conditions to produce.', 'STYLES', array['Sweet', 'Rare']::text[], '#C9A227', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Full","acidity":"High","keyRegions":["Canada","Germany","Austria"],"notableGrapes":["Riesling","Vidal","Cabernet Franc"],"classification":"STYLE"}'::jsonb, null, null),
  ('S019', 'Botrytis Wine', 'Noble rot sweet wines where Botrytis cinerea fungus concentrates grape sugars while adding honeyed complexity. Sauternes and Tokaji are the most famous examples.', 'STYLES', array['Noble Rot', 'Luxury']::text[], '#C9A227', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Full","acidity":"High","keyRegions":["Sauternes","Tokaj","Germany"],"notableGrapes":["Sémillon","Furmint","Riesling"],"classification":"STYLE"}'::jsonb, null, null),
  ('S020', 'GSM Blend', 'Classic Rhône-style blend of Grenache, Syrah, and Mourvèdre creating complex, balanced reds. Each grape contributes fruit, structure, and aromatics to the final wine.', 'STYLES', array['Blend', 'Rhône']::text[], '#800020', 'circle', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Various","body":"Medium-Full","tannin":"Medium","keyRegions":["Rhône","Australia","California"],"notableGrapes":["Grenache","Syrah","Mourvèdre"],"classification":"BLEND"}'::jsonb, null, null),
  ('S021', 'Bordeaux Blend', 'Classic blend dominated by Cabernet Sauvignon and Merlot with supporting varieties. This noble style has been replicated worldwide for its structure and aging potential.', 'STYLES', array['Classic', 'Blend']::text[], '#722F37', 'shield', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"France","body":"Full","tannin":"High","keyRegions":["Bordeaux","Napa","Margaret River"],"notableGrapes":["Cabernet Sauvignon","Merlot","Cabernet Franc","Petit Verdot"],"classification":"BLEND"}'::jsonb, null, null),
  ('S022', 'Super Tuscan', 'Non-traditional Italian wines that broke from DOC rules by blending international varieties with local grapes. These innovative wines put modern Italian winemaking on the map.', 'STYLES', array['Italian', 'Modern']::text[], '#722F37', 'flame', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"Italy","body":"Full","tannin":"High","keyRegions":["Tuscany"],"notableGrapes":["Cabernet Sauvignon","Merlot","Sangiovese"],"classification":"BLEND"}'::jsonb, null, null),
  ('S023', 'Cru Beaujolais', 'Age-worthy Gamay from the ten named villages of Beaujolais, offering serious wines beyond simple Nouveau. Each cru has distinct character from its unique granite-based terroir.', 'STYLES', array['Gamay', 'Cru']::text[], '#D4A5A5', 'mountain', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"France","body":"Medium","tannin":"Low-Medium","keyRegions":["Beaujolais"],"notableGrapes":["Gamay"],"classification":"STYLE"}'::jsonb, null, null),
  ('S024', 'Crémant', 'French sparkling wines made in the traditional method outside Champagne, offering excellent value. Crémant d''Alsace, Loire, and Burgundy are the most notable examples.', 'STYLES', array['Sparkling', 'Value']::text[], '#D4B896', 'sparkles', 'style', 'style', null, '[]'::jsonb, null, null, '{"origin":"France","body":"Light","acidity":"High","keyRegions":["Alsace","Loire","Burgundy"],"notableGrapes":["Chardonnay","Chenin Blanc","Pinot Blanc"],"classification":"STYLE"}'::jsonb, null, null),
